/* url-parts example: find and parse all URLs in text.
 * stub.h and stub.c are auto-generated by: regexped generate
 *
 * Iterate URLs with:
 *   const rx_group_t *g = parse_url(input, len, off);
 *   if (g[0].start < 0) break;  // no more matches
 *   off = (unsigned int)g[0].end;
 */
#include "stub.h"

/* ---- minimal WASI glue (no libc needed) --------------------------------- */

__attribute__((import_module("wasi_snapshot_preview1"), import_name("args_sizes_get")))
extern int wasi_args_sizes_get(unsigned int *argc, unsigned int *argv_buf_size);

__attribute__((import_module("wasi_snapshot_preview1"), import_name("args_get")))
extern int wasi_args_get(char **argv, char *argv_buf);

__attribute__((import_module("wasi_snapshot_preview1"), import_name("fd_write")))
extern int wasi_fd_write(int fd, const void *iovs, int iovs_len, int *nwritten);

__attribute__((import_module("wasi_snapshot_preview1"), import_name("proc_exit")))
__attribute__((noreturn))
extern void wasi_proc_exit(int code);

struct iov { const void *buf; unsigned int len; };

static unsigned int my_strlen(const char *s) {
    unsigned int n = 0;
    while (s[n]) n++;
    return n;
}

static void my_write(const char *s, unsigned int len) {
    int nw;
    struct iov v = { s, len };
    wasi_fd_write(1, &v, 1, &nw);
}

static void my_puts(const char *s) {
    my_write(s, my_strlen(s));
    my_write("\n", 1);
}

static void my_write_slice(const char *s, int start, int end) {
    my_write(s + start, (unsigned int)(end - start));
}

/* ---- main ---------------------------------------------------------------- */

__attribute__((export_name("_start")))
void _start(void) {
    unsigned int argc, buf_size;
    wasi_args_sizes_get(&argc, &buf_size);
    char *argv_buf = __builtin_alloca(buf_size + 1);
    char **argv = __builtin_alloca(argc * sizeof(char *));
    wasi_args_get(argv, argv_buf);

    if (argc < 2) {
        my_puts("Usage: url_parts <text>");
        wasi_proc_exit(1);
    }

    const char *text = argv[1];
    unsigned int len = my_strlen(text);
    const unsigned char *input = (const unsigned char *)text;

    int found = 0;
    unsigned int off = 0;
    while (off <= len) {
        const rx_group_t *groups = parse_url(input, len, off);
        if (groups[0].start < 0) break;
        found = 1;
        my_puts("URL:");
        for (int i = 1; i < PARSE_URL_GROUPS; i++) {
            if (!groups[i].name || groups[i].start < 0) continue;
            my_write("  ", 2);
            unsigned int nlen = my_strlen(groups[i].name);
            my_write(groups[i].name, nlen);
            /* pad to 10 chars */
            for (unsigned int p = nlen; p < 10; p++) my_write(" ", 1);
            my_write(" = ", 3);
            my_write_slice(text, groups[i].start, groups[i].end);
            my_write("\n", 1);
        }
        off = (unsigned int)(groups[0].end > groups[0].start
                             ? groups[0].end : groups[0].start + 1);
    }
    if (!found) {
        my_puts("No URLs found");
    }
    wasi_proc_exit(0);
}
